def tela_relatorios_exportacao():
    st.subheader("Relatórios e exportação")

    lista = filtros_base(atendimentos())
    df = atendimentos_df(lista)

    if df.empty:
        st.info("Nenhum registro para exportar.")
        return

    st.markdown("#### Base filtrada")
    st.dataframe(df, use_container_width=True, hide_index=True)

    st.divider()

    col1, col2 = st.columns(2)

    with col1:
        st.markdown("#### Relatório por status")
        st.dataframe(df["Status"].value_counts().rename_axis("Status").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

        st.markdown("#### Relatório por servidor")
        st.dataframe(df["Servidor(a)"].value_counts().rename_axis("Servidor(a)").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

    with col2:
        st.markdown("#### Relatório por assunto")
        st.dataframe(df["Assunto"].value_counts().rename_axis("Assunto").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

        st.markdown("#### Relatório por fonte")
        st.dataframe(df["Fonte"].value_counts().rename_axis("Fonte").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

    st.divider()

    buffer = BytesIO()
    with pd.ExcelWriter(buffer, engine="openpyxl") as writer:
        df.to_excel(writer, index=False, sheet_name="Atendimentos")
        df["Status"].value_counts().rename_axis("Status").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por status")
        df["Servidor(a)"].value_counts().rename_axis("Servidor(a)").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por servidor")
        df["Assunto"].value_counts().rename_axis("Assunto").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por assunto")
        df["Fonte"].value_counts().rename_axis("Fonte").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por fonte")

    st.download_button(
        "Baixar relatório em Excel",
        data=buffer.getvalue(),
        file_name=f"relatorio_atendimentos_sepro_{agora_brasilia().strftime('%Y%m%d_%H%M')}.xlsx",
        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )

    csv = df.to_csv(index=False, sep=";").encode("utf-8-sig")
    st.download_button(
        "Baixar base em CSV",
        data=csv,
        file_name=f"base_atendimentos_sepro_{agora_brasilia().strftime('%Y%m%d_%H%M')}.csv",
        mime="text/csv"
    )


def tela_assuntos():
    st.subheader("Assuntos")
    st.caption("Área exclusiva do administrador.")

    lista = assuntos()

    with st.form("form_assunto"):
        novo = st.text_input("Novo assunto")
        if st.form_submit_button("Adicionar assunto"):
            if not novo.strip():
                st.warning("Informe um assunto.")
            else:
                lista.append(novo.strip())
                salvar_assuntos(lista)
                st.success("Assunto adicionado.")
                st.rerun()

    st.divider()
    st.markdown("#### Assuntos triagems")

    for assunto in lista:
        col1, col2 = st.columns([4, 1])
        col1.write(assunto)
        if col2.button("Excluir", key=f"del_assunto_{assunto}"):
            nova_lista = [a for a in lista if a != assunto]
            salvar_assuntos(nova_lista)
            st.success("Assunto removido da lista de opções. Registros antigos foram preservados.")
            st.rerun()


def tela_usuarios():
    st.subheader("Usuários")
    st.caption("Área exclusiva do administrador.")

    lista = usuarios()
    df = pd.DataFrame(lista)

    if not df.empty:
        exibir = df.copy()
        for col in ["senha_hash", "token_validacao", "token_recuperacao"]:
            if col in exibir.columns:
                exibir = exibir.drop(columns=[col])
        st.dataframe(exibir, use_container_width=True, hide_index=True)
    else:
        st.info("Nenhum usuário triagem.")

    st.divider()

    st.markdown("#### Gerenciar usuário")

    opcoes = [f"{u.get('nome')} - {u.get('email')}" for u in lista]
    if not opcoes:
        return

    selecionado = st.selectbox("Selecione o usuário", opcoes)
    email_sel = selecionado.split(" - ")[-1]

    usuario = next((u for u in lista if u.get("email") == email_sel), None)
    if not usuario:
        return

    col1, col2, col3 = st.columns(3)

    with col1:
        novo_perfil = st.selectbox(
            "Perfil",
            ["Administrador", "Usuário"],
            index=0 if usuario.get("perfil") == "Administrador" else 1
        )

    with col2:
        ativo = st.checkbox("Ativo", value=usuario.get("ativo", True))

    with col3:
        validado = st.checkbox("Validado", value=usuario.get("validado", False))

    if st.button("Salvar alterações do usuário"):
        usuario["perfil"] = novo_perfil
        usuario["ativo"] = ativo
        usuario["validado"] = validado
        salvar_usuarios(lista)
        st.success("Usuário atualizado.")
        st.rerun()

    st.divider()
    st.markdown("#### Excluir usuário")

    email_logado = usuario_logado().get("email")

    if usuario.get("email") == email_logado:
        st.warning("Você não pode excluir o próprio usuário enquanto estiver logado.")
    else:
        admins_ativos = [
            u for u in lista
            if u.get("perfil") == "Administrador" and u.get("ativo", True) and u.get("email") != usuario.get("email")
        ]

        if usuario.get("perfil") == "Administrador" and not admins_ativos:
            st.warning("Não é permitido excluir o último administrador ativo.")
        else:
            confirmar = st.checkbox(f"Confirmo a exclusão de {usuario.get('email')}")
            if st.button("Excluir usuário", type="secondary"):
                if not confirmar:
                    st.warning("Marque a confirmação antes de excluir.")
                else:
                    nova_lista = [u for u in lista if u.get("email") != usuario.get("email")]
                    salvar_usuarios(nova_lista)
                    st.success("Usuário excluído.")
                    st.rerun()



def tela_backup_restauracao():
    st.subheader("Backup e restauração")
    st.warning(
        "O Streamlit Community Cloud pode apagar arquivos internos quando o aplicativo reinicia. "
        "Por isso, baixe um backup regularmente, especialmente ao final do expediente ou após muitos lançamentos."
    )

    backup = montar_backup_completo()
    nome_backup = f"backup_completo_sistema_sepro_{agora_brasilia().strftime('%Y%m%d_%H%M%S')}.json"
    dados_json = json.dumps(backup, ensure_ascii=False, indent=2).encode("utf-8")

    st.markdown("### Baixar backup completo")
    st.write("Este arquivo permite restaurar atendimentos, usuários e assuntos caso o sistema perca os registros.")

    st.download_button(
        "Baixar backup completo em JSON",
        data=dados_json,
        file_name=nome_backup,
        mime="application/json",
        type="primary"
    )

    atend = atendimentos_df(atendimentos())
    usuarios_df = pd.DataFrame(usuarios())
    assuntos_df = pd.DataFrame({"Assunto": assuntos()})

    buffer = BytesIO()
    with pd.ExcelWriter(buffer, engine="openpyxl") as writer:
        atend.to_excel(writer, index=False, sheet_name="Atendimentos")
        usuarios_df.drop(columns=[c for c in ["senha_hash", "token_validacao", "token_recuperacao"] if c in usuarios_df.columns], errors="ignore").to_excel(writer, index=False, sheet_name="Usuarios")
        assuntos_df.to_excel(writer, index=False, sheet_name="Assuntos")

    st.download_button(
        "Baixar cópia em Excel para conferência",
        data=buffer.getvalue(),
        file_name=f"copia_conferencia_sistema_sepro_{agora_brasilia().strftime('%Y%m%d_%H%M%S')}.xlsx",
        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )

    st.divider()

    st.markdown("### Restaurar backup")
    st.info("Use esta opção quando os registros sumirem ou quando for necessário recuperar uma cópia anterior.")

    arquivo_backup = st.file_uploader("Enviar arquivo de backup JSON", type=["json"])

    if arquivo_backup is not None:
        try:
            conteudo = arquivo_backup.read().decode("utf-8")
            dados = json.loads(conteudo)

            st.write("Backup carregado para conferência:")
            st.write(f"- Atendimentos: **{len(dados.get('atendimentos', []))}**")
            st.write(f"- Usuários: **{len(dados.get('usuarios', []))}**")
            st.write(f"- Assuntos: **{len(dados.get('assuntos', []))}**")

            confirmar = st.checkbox("Confirmo que desejo restaurar este backup e substituir os dados atuais.")

            if st.button("Restaurar backup", type="primary"):
                if not confirmar:
                    st.warning("Marque a confirmação antes de restaurar.")
                else:
                    restaurar_backup_completo(dados)
                    st.success("Backup restaurado com sucesso. Reinicie ou atualize o aplicativo.")
                    st.rerun()

        except Exception as erro:
            st.error("Não foi possível ler ou restaurar o backup.")
            st.write(erro)

    st.divider()

    st.markdown("### Backups locais automáticos")
    st.caption(
        "O sistema tenta criar backups locais a cada alteração. Eles ajudam em reinicializações curtas, "
        "mas não substituem o download do backup completo, pois arquivos locais podem ser apagados pela hospedagem."
    )

    try:
        PASTA_BACKUPS.mkdir(exist_ok=True)
        arquivos = sorted(PASTA_BACKUPS.glob("backup_*.json"), key=lambda p: p.stat().st_mtime, reverse=True)

        if not arquivos:
            st.info("Ainda não há backup local automático disponível.")
        else:
            for arq in arquivos[:10]:
                with open(arq, "rb") as f:
                    st.download_button(
                        f"Baixar {arq.name}",
                        data=f.read(),
                        file_name=arq.name,
                        mime="application/json",
                        key=f"download_{arq.name}"
                    )
    except Exception as erro:
        st.warning("Não foi possível listar os backups locais automáticos.")
        st.write(erro)



